    const nounSuffix = (w.endsWith("tion") || w.endsWith("sion") ? 0.75 : 0) + (w.endsWith("ment") ? 0.65 : 0) + (w.endsWith("ness") ? 0.65 : 0) + (w.endsWith("ity") || w.endsWith("ety") ? 0.6 : 0) + (w.endsWith("age") && len > 4 ? 0.4 : 0) + (w.endsWith("er") && len > 4 && !w.endsWith("her") ? 0.25 : 0) + (w.endsWith("or") && len > 4 ? 0.25 : 0) + (w.endsWith("ist") && len > 4 ? 0.4 : 0);
