        "pig",
        "hat",
        "sun",
        "red",
        "big",
        "mom",
        "dad",
        "run",
        "eat",
        "yes",
        "no",
        "up",
        "hi",
        "bed",
        "hot",
        "top",
        "fox",
        "bug"
