    const mood = iv.mood || "0/0/0";
    const moodHue = (ivValence >= 0 ? 330 : 240) + ivValence * 30;
    const moodSat = 50 + ivArousal * 50;
    const moodLight = 40 + (iv.coherence ?? 0.5) * 20;
