    this._connCol[ci + 1] = colorA[1];
    this._connCol[ci + 2] = colorA[2];
    this._connCol[ci + 3] = alpha;
    this._connCol[ci + 4] = colorB[0];
    this._connCol[ci + 5] = colorB[1];
