        const srcIdx = offsets[srcCI] + Math.floor(Math.random() * srcN);
        const tgtIdx = offsets[tgtCI] + Math.floor(Math.random() * CLUSTERS[tgtCI].n);
        if (srcIdx >= TOTAL || tgtIdx >= TOTAL) continue;
