      srcBuf[p6 + 1] = tr.src[1];
      srcBuf[p6 + 2] = tr.src[2];
      srcBuf[p6 + 3] = tr.src[0];
      srcBuf[p6 + 4] = tr.src[1];
      srcBuf[p6 + 5] = tr.src[2];
