      tgtBuf[p6 + 1] = tr.tgt[1];
      tgtBuf[p6 + 2] = tr.tgt[2];
      tgtBuf[p6 + 3] = tr.tgt[0];
      tgtBuf[p6 + 4] = tr.tgt[1];
      tgtBuf[p6 + 5] = tr.tgt[2];
