    const arousal = state?.amygdala?.arousal || 0.5;
    const noise = Math.sin(Date.now() * 8e-3 * (1 + arousal)) * 0.2 + Math.sin(Date.now() * 0.023) * 0.1 + (Math.random() - 0.5) * 0.08;
